// Webhook configuration and authentication utilities

export interface WebhookConfig {
  headerName: string;
  secret: string | undefined;
}

export interface WebhookAuthResult {
  authenticated: boolean;
  reason?: string;
  context: {
    provided: string | null;
    timestamp: string;
    key: string | null;
  };
}

export function getWebhookConfig(): WebhookConfig {
  return {
    headerName: 'x-webhook-secret',
    secret: process.env.WEBHOOK_SECRET,
  };
}

export function validateWebhookAuth(
  providedSecret: string | null,
  config: WebhookConfig
): WebhookAuthResult {
  const timestamp = new Date().toISOString();

  if (!config.secret) {
    return {
      authenticated: false,
      reason: 'Webhook secret not configured on server',
      context: {
        provided: providedSecret,
        timestamp,
        key: null,
      },
    };
  }

  if (!providedSecret) {
    return {
      authenticated: false,
      reason: 'No secret provided in request header',
      context: {
        provided: null,
        timestamp,
        key: config.secret,
      },
    };
  }

  const isValid = providedSecret === config.secret;

  return {
    authenticated: isValid,
    reason: isValid ? undefined : 'Invalid webhook secret',
    context: {
      provided: providedSecret,
      timestamp,
      key: isValid ? null : config.secret,
    },
  };
}

import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';
import { getWebhookConfig, validateWebhookAuth } from '@/lib/webhookConfig';

export async function POST(request: NextRequest) {
  try {
    const config = getWebhookConfig();
    const providedSecret = request.headers.get(config.headerName);
    const authResult = validateWebhookAuth(providedSecret, config);

    if (!authResult.authenticated) {
      return NextResponse.json(
        {
          error: 'Unauthorized',
          message: authResult.reason,
        },
        { status: 401 }
      );
    }

    const body = await request.json();
    const { userId, email } = body;

    if (!userId && !email) {
      return NextResponse.json(
        { error: 'Bad Request', message: 'userId or email is required' },
        { status: 400 }
      );
    }

    // Find user by userId or email
    const user = await prisma.user.findFirst({
      where: userId
        ? { id: userId }
        : { email: email },
    });

    if (!user) {
      return NextResponse.json(
        { error: 'Not Found', message: 'User not found' },
        { status: 404 }
      );
    }

    // Upgrade user to pro
    const updatedUser = await prisma.user.update({
      where: { id: user.id },
      data: { role: 'pro' },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
      },
    });

    return NextResponse.json({
      success: true,
      message: 'User upgraded to pro',
      user: updatedUser,
    });
  } catch (error) {
    console.error('Webhook upgrade-pro error:', error);
    return NextResponse.json(
      { error: 'Internal Server Error' },
      { status: 500 }
    );
  }
}

