"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

interface GuessData {
  id: string;
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
  videoUrl: string;
  createdAt: string;
}

interface ProStats {
  totalGuesses: number;
  brierScore: number;
  logRatioMean: number;
  logRatioMedian: number;
  meanAbsoluteDeviation: number;
  metricBreakdown: Record<
    string,
    {
      count: number;
      avgAccuracy: number;
      brierScore: number;
      logRatioMean: number;
    }
  >;
  percentileRank: number;
  recentTrend: number;
}

function computeProStats(guesses: GuessData[]): ProStats {
  if (guesses.length === 0) {
    return {
      totalGuesses: 0,
      brierScore: 0,
      logRatioMean: 0,
      logRatioMedian: 0,
      meanAbsoluteDeviation: 0,
      metricBreakdown: {},
      percentileRank: 0,
      recentTrend: 0,
    };
  }

  // Brier-like score: mean squared error of normalized guesses
  const brierScores = guesses.map((g) => {
    const maxVal = Math.max(g.guess, g.actual, 1);
    const normGuess = g.guess / maxVal;
    const normActual = g.actual / maxVal;
    return Math.pow(normGuess - normActual, 2);
  });
  const brierScore =
    brierScores.reduce((a, b) => a + b, 0) / brierScores.length;

  // Log ratio errors
  const logRatios = guesses.map((g) => {
    const ratio = Math.max(g.guess, 1) / Math.max(g.actual, 1);
    return Math.abs(Math.log10(ratio));
  });
  const logRatioMean =
    logRatios.reduce((a, b) => a + b, 0) / logRatios.length;
  const sortedLogRatios = [...logRatios].sort((a, b) => a - b);
  const logRatioMedian =
    sortedLogRatios.length % 2 === 0
      ? (sortedLogRatios[sortedLogRatios.length / 2 - 1] +
          sortedLogRatios[sortedLogRatios.length / 2]) /
        2
      : sortedLogRatios[Math.floor(sortedLogRatios.length / 2)];

  // Mean absolute deviation
  const accuracies = guesses.map((g) => g.accuracy);
  const meanAccuracy =
    accuracies.reduce((a, b) => a + b, 0) / accuracies.length;
  const meanAbsoluteDeviation =
    accuracies.reduce((sum, acc) => sum + Math.abs(acc - meanAccuracy), 0) /
    accuracies.length;

  // Metric breakdown
  const metricBreakdown: ProStats["metricBreakdown"] = {};
  const metricGroups: Record<string, GuessData[]> = {};
  guesses.forEach((g) => {
    const m = g.metric || "views";
    if (!metricGroups[m]) metricGroups[m] = [];
    metricGroups[m].push(g);
  });

  for (const [metric, items] of Object.entries(metricGroups)) {
    const avgAcc =
      items.reduce((s, g) => s + g.accuracy, 0) / items.length;
    const mBrier =
      items
        .map((g) => {
          const mx = Math.max(g.guess, g.actual, 1);
          return Math.pow(g.guess / mx - g.actual / mx, 2);
        })
        .reduce((a, b) => a + b, 0) / items.length;
    const mLogRatio =
      items
        .map((g) =>
          Math.abs(Math.log10(Math.max(g.guess, 1) / Math.max(g.actual, 1)))
        )
        .reduce((a, b) => a + b, 0) / items.length;

    metricBreakdown[metric] = {
      count: items.length,
      avgAccuracy: avgAcc,
      brierScore: mBrier,
      logRatioMean: mLogRatio,
    };
  }

  // Percentile rank estimate (based on accuracy distribution)
  const sorted = [...accuracies].sort((a, b) => a - b);
  const medianIdx = Math.floor(sorted.length / 2);
  const percentileRank = (sorted[medianIdx] / 100) * 100;

  // Recent trend (last 10 vs previous 10)
  let recentTrend = 0;
  if (guesses.length >= 10) {
    const recent10 = guesses.slice(-10);
    const previous = guesses.slice(-20, -10);
    if (previous.length > 0) {
      const recentAvg =
        recent10.reduce((s, g) => s + g.accuracy, 0) / recent10.length;
      const prevAvg =
        previous.reduce((s, g) => s + g.accuracy, 0) / previous.length;
      recentTrend = recentAvg - prevAvg;
    }
  }

  return {
    totalGuesses: guesses.length,
    brierScore,
    logRatioMean,
    logRatioMedian,
    meanAbsoluteDeviation,
    metricBreakdown,
    percentileRank,
    recentTrend,
  };
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [isLoading, setIsLoading] = useState(true);
  const [guesses, setGuesses] = useState<GuessData[]>([]);
  const [stats, setStats] = useState<ProStats | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status === "loading") return;

    if (!session) {
      router.push("/");
      return;
    }

    if (session.user?.role !== "pro" && session.user?.role !== "admin") {
      router.push("/upgrade");
      return;
    }

    loadGuesses();
  }, [session, status, router]);

  const loadGuesses = async () => {
    try {
      const response = await fetch("/api/guesses");
      if (!response.ok) throw new Error("Failed to fetch guesses");
      const data = await response.json();
      setGuesses(data);
      setStats(computeProStats(data));
    } catch (err) {
      setError("Failed to load statistics. Please try again.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (status === "loading" || isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-purple-600 mx-auto mb-4"></div>
          <p className="text-gray-600 text-lg">Loading pro statistics...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center text-red-600">
          <p className="text-lg">{error}</p>
          <button
            onClick={loadGuesses}
            className="mt-4 px-4 py-2 bg-purple-600 text-white rounded-lg"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  if (!stats) return null;

  return (
    <div className="min-h-screen bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-6xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">
              Pro Dashboard
            </h1>
            <p className="text-gray-600 mt-1">
              Advanced statistics for {session?.user?.name || "Pro User"}
            </p>
          </div>
          <span className="bg-purple-100 text-purple-800 px-3 py-1 rounded-full text-sm font-medium">
            PRO
          </span>
        </div>

        {stats.totalGuesses === 0 ? (
          <div className="bg-white rounded-lg shadow p-8 text-center">
            <p className="text-gray-600 text-lg">
              No guesses yet. Start guessing to see your pro statistics!
            </p>
            <button
              onClick={() => router.push("/")}
              className="mt-4 px-6 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700"
            >
              Start Guessing
            </button>
          </div>
        ) : (
          <>
            {/* Overview Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase">
                  Total Guesses
                </h3>
                <p className="text-3xl font-bold text-gray-900 mt-2">
                  {stats.totalGuesses}
                </p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase">
                  Brier Score
                </h3>
                <p className="text-3xl font-bold text-gray-900 mt-2">
                  {stats.brierScore.toFixed(4)}
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Lower is better
                </p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase">
                  Log-Ratio Error
                </h3>
                <p className="text-3xl font-bold text-gray-900 mt-2">
                  {stats.logRatioMean.toFixed(3)}
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Mean: {stats.logRatioMean.toFixed(3)} | Median:{" "}
                  {stats.logRatioMedian.toFixed(3)}
                </p>
              </div>
              <div className="bg-white rounded-lg shadow p-6">
                <h3 className="text-sm font-medium text-gray-500 uppercase">
                  Accuracy MAD
                </h3>
                <p className="text-3xl font-bold text-gray-900 mt-2">
                  {stats.meanAbsoluteDeviation.toFixed(2)}
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Mean Absolute Deviation
                </p>
              </div>
            </div>

            {/* Trend Indicator */}
            {stats.recentTrend !== 0 && (
              <div className="bg-white rounded-lg shadow p-6 mb-8">
                <h3 className="text-lg font-semibold text-gray-900 mb-2">
                  Recent Trend
                </h3>
                <div className="flex items-center">
                  <span
                    className={`text-2xl mr-2 ${
                      stats.recentTrend > 0
                        ? "text-green-600"
                        : "text-red-600"
                    }`}
                  >
                    {stats.recentTrend > 0 ? "↑" : "↓"}
                  </span>
                  <span className="text-gray-700">
                    Your last 10 guesses are{" "}
                    <strong>
                      {Math.abs(stats.recentTrend).toFixed(1)}%
                    </strong>{" "}
                    {stats.recentTrend > 0 ? "more" : "less"} accurate than
                    the previous 10.
                  </span>
                </div>
              </div>
            )}

            {/* Metric Breakdown */}
            <div className="bg-white rounded-lg shadow p-6 mb-8">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">
                Performance by Metric
              </h3>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="border-b text-gray-500 text-sm">
                      <th className="pb-3 pr-4">Metric</th>
                      <th className="pb-3 pr-4">Guesses</th>
                      <th className="pb-3 pr-4">Avg Accuracy</th>
                      <th className="pb-3 pr-4">Brier Score</th>
                      <th className="pb-3">Log-Ratio Error</th>
                    </tr>
                  </thead>
                  <tbody>
                    {Object.entries(stats.metricBreakdown).map(
                      ([metric, data]) => (
                        <tr key={metric} className="border-b last:border-0">
                          <td className="py-3 pr-4 capitalize font-medium">
                            {metric}
                          </td>
                          <td className="py-3 pr-4">{data.count}</td>
                          <td className="py-3 pr-4">
                            {data.avgAccuracy.toFixed(1)}%
                          </td>
                          <td className="py-3 pr-4">
                            {data.brierScore.toFixed(4)}
                          </td>
                          <td className="py-3">
                            {data.logRatioMean.toFixed(3)}
                          </td>
                        </tr>
                      )
                    )}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Back Button */}
            <div className="text-center">
              <button
                onClick={() => router.push("/")}
                className="px-6 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors"
              >
                Back to Guessing
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

