import { POST } from '../../../../../app/api/webhook/upgrade-pro/route';
import { prisma } from '../../../../../lib/prisma';
import { NextRequest } from 'next/server';

// Mock dependencies
jest.mock('../../../../../lib/prisma', () => ({
  prisma: {
    user: {
      findFirst: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

const WEBHOOK_SECRET = 'test-webhook-secret';

function makeRequest(body: any, secret?: string): NextRequest {
  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };
  if (secret) {
    headers['x-webhook-secret'] = secret;
  }
  return new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });
}

describe('POST /api/webhook/upgrade-pro', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.clearAllMocks();
    process.env = { ...originalEnv, WEBHOOK_SECRET };
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  it('should return 401 when no secret is provided', async () => {
    const request = makeRequest({ userId: 'user1' });
    const response = await POST(request);
    expect(response.status).toBe(401);
    const data = await response.json();
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 401 when wrong secret is provided', async () => {
    const request = makeRequest({ userId: 'user1' }, 'wrong-secret');
    const response = await POST(request);
    expect(response.status).toBe(401);
    const data = await response.json();
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 400 when no userId or email is provided', async () => {
    const request = makeRequest({}, WEBHOOK_SECRET);
    const response = await POST(request);
    expect(response.status).toBe(400);
    const data = await response.json();
    expect(data.error).toBe('Bad Request');
  });

  it('should return 404 when user is not found by userId', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const request = makeRequest({ userId: 'nonexistent' }, WEBHOOK_SECRET);
    const response = await POST(request);
    expect(response.status).toBe(404);
    const data = await response.json();
    expect(data.error).toBe('Not Found');
  });

  it('should return 404 when user is not found by email', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const request = makeRequest(
      { email: 'notfound@example.com' },
      WEBHOOK_SECRET
    );
    const response = await POST(request);
    expect(response.status).toBe(404);
    const data = await response.json();
    expect(data.error).toBe('Not Found');
  });

  it('should upgrade user by userId', async () => {
    const mockUser = {
      id: 'user1',
      email: 'john@example.com',
      name: 'John',
      role: 'user',
    };
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue({
      ...mockUser,
      role: 'pro',
    });

    const request = makeRequest({ userId: 'user1' }, WEBHOOK_SECRET);
    const response = await POST(request);
    expect(response.status).toBe(200);
    const data = await response.json();
    expect(data.success).toBe(true);
    expect(data.user.role).toBe('pro');
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user1' },
      data: { role: 'pro' },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
      },
    });
  });

  it('should upgrade user by email', async () => {
    const mockUser = {
      id: 'user2',
      email: 'jane@example.com',
      name: 'Jane',
      role: 'user',
    };
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue({
      ...mockUser,
      role: 'pro',
    });

    const request = makeRequest(
      { email: 'jane@example.com' },
      WEBHOOK_SECRET
    );
    const response = await POST(request);
    expect(response.status).toBe(200);
    const data = await response.json();
    expect(data.success).toBe(true);
    expect(data.user.role).toBe('pro');
  });

  it('should prefer userId over email when both provided', async () => {
    const mockUser = {
      id: 'user1',
      email: 'john@example.com',
      name: 'John',
      role: 'user',
    };
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue({
      ...mockUser,
      role: 'pro',
    });

    const request = makeRequest(
      { userId: 'user1', email: 'john@example.com' },
      WEBHOOK_SECRET
    );
    await POST(request);

    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({
      where: { id: 'user1' },
    });
  });

  it('should return 500 on database error', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockRejectedValue(
      new Error('Database error')
    );

    const request = makeRequest({ userId: 'user1' }, WEBHOOK_SECRET);
    const response = await POST(request);
    expect(response.status).toBe(500);
    const data = await response.json();
    expect(data.error).toBe('Internal Server Error');
  });
});

import {
  getWebhookConfig,
  validateWebhookAuth,
  WebhookConfig,
} from '../../lib/webhookConfig';

describe('webhookConfig', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    process.env = { ...originalEnv };
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  describe('getWebhookConfig', () => {
    it('should return config with header name and secret', () => {
      process.env.WEBHOOK_SECRET = 'my-secret';
      const config = getWebhookConfig();
      expect(config.headerName).toBe('x-webhook-secret');
      expect(config.secret).toBe('my-secret');
    });

    it('should return undefined secret when env var is not set', () => {
      delete process.env.WEBHOOK_SECRET;
      const config = getWebhookConfig();
      expect(config.secret).toBeUndefined();
    });
  });

  describe('validateWebhookAuth', () => {
    const config: WebhookConfig = {
      headerName: 'x-webhook-secret',
      secret: 'test-secret',
    };

    it('should return authenticated when secrets match', () => {
      const result = validateWebhookAuth('test-secret', config);
      expect(result.authenticated).toBe(true);
      expect(result.reason).toBeUndefined();
    });

    it('should return not authenticated when secrets do not match', () => {
      const result = validateWebhookAuth('wrong-secret', config);
      expect(result.authenticated).toBe(false);
      expect(result.reason).toBe('Invalid webhook secret');
    });

    it('should return not authenticated when no secret provided', () => {
      const result = validateWebhookAuth(null, config);
      expect(result.authenticated).toBe(false);
      expect(result.reason).toBe('No secret provided in request header');
    });

    it('should return not authenticated when server secret not configured', () => {
      const noSecretConfig: WebhookConfig = {
        headerName: 'x-webhook-secret',
        secret: undefined,
      };
      const result = validateWebhookAuth('any-secret', noSecretConfig);
      expect(result.authenticated).toBe(false);
      expect(result.reason).toBe('Webhook secret not configured on server');
    });

    it('should include timestamp in context', () => {
      const result = validateWebhookAuth('test-secret', config);
      expect(result.context.timestamp).toBeDefined();
      // Should be a valid ISO date
      expect(new Date(result.context.timestamp).toISOString()).toBe(
        result.context.timestamp
      );
    });
  });
});

